class Solution:
    def maxProduct(self, s):
        n = len(s)
        best = 0
        def rec(i, a, b):
            nonlocal best
            if i == n:
                if a == a[::-1] and b == b[::-1]:
                    prod = len(a) * len(b)
                    if prod > best:
                        best = prod
                return
            rec(i + 1, a + s[i], b)
            rec(i + 1, a, b + s[i])
            rec(i + 1, a, b)
        rec(0, '', '')
        return best

