class Solution:
    def maxProduct(self, s):
        n = len(s)
        def is_pal(mask):
            chars = [s[i] for i in range(n) if mask & (1 << i)]
            return chars == chars[::-1]
        pal_masks = [m for m in range(1 << n) if is_pal(m)]
        pal_set = set(pal_masks)
        best = 0
        full = (1 << n) - 1
        for m1 in pal_masks:
            c1 = bin(m1).count('1')
            comp = full ^ m1
            sub = comp
            while True:
                if sub in pal_set:
                    c2 = bin(sub).count('1')
                    if c1 * c2 > best:
                        best = c1 * c2
                if sub == 0:
                    break
                sub = (sub - 1) & comp
        return best

