var maxProduct = function(s) {
    const n = s.length;
    const isPal = (mask) => {
        const chars = [];
        for (let i = 0; i < n; i++) if (mask & (1 << i)) chars.push(s[i]);
        for (let i = 0, j = chars.length - 1; i < j; i++, j--) {
            if (chars[i] !== chars[j]) return false;
        }
        return true;
    };
    const popcount = (x) => { let c = 0; while (x) { c += x & 1; x >>= 1; } return c; };
    const full = (1 << n) - 1;
    const palMasks = [];
    const palSet = new Set();
    for (let m = 0; m <= full; m++) {
        if (isPal(m)) { palMasks.push(m); palSet.add(m); }
    }
    let best = 0;
    for (const m1 of palMasks) {
        const c1 = popcount(m1);
        const comp = full ^ m1;
        let sub = comp;
        while (true) {
            if (palSet.has(sub)) {
                const c2 = popcount(sub);
                if (c1 * c2 > best) best = c1 * c2;
            }
            if (sub === 0) break;
            sub = (sub - 1) & comp;
        }
    }
    return best;
};
